import React, { useState, useEffect } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://oauth2provider.com/auth';
const tokenEndpoint = 'https://oauth2provider.com/token';

const App = () => {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('access_token'));

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      fetchAccessToken(code);
    }
  }, []);

  const getAuthCode = () => {
    const authUrl = `${authEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
    window.location = authUrl;
  };

  const fetchAccessToken = async (code) => {
    const response = await fetch(tokenEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code,
        redirect_uri: redirectUri,
        client_id: clientId,
      }),
    });
    const data = await response.json();
    if (data.access_token) {
      localStorage.setItem('access_token', data.access_token);
      setAccessToken(data.access_token);
    }
  };

  return (
    <div>
      <h1>OAuth 2.0 SPA</h1>
      {!accessToken ? (
        <button onClick={getAuthCode}>Login with OAuth</button>
      ) : (
        <p>Authenticated</p>
      )}
    </div>
  );
};

export default App;